using System;using System.Collections.Generic;using System.Linq;class A{static string s;static Dictionary<string,int>D=new();static Dictionary<int,long>C=new();static string[]M={".-","-...","-.-.","-..",".","..-.","--.","....","..",".---","-.-",".-..","--","-.","---",".--.","--.-",".-.","...","-","..-","...-",".--","-..-","-.--","--.."};static long F(int i){if(i==s.Length)return 1;if(C.ContainsKey(i))return C[i];long r=0;foreach(var e in D){if(s.AsSpan(i).StartsWith(e.Key))r+=e.Value*F(i+e.Key.Length);}return C[i]=r;}static void Main(){s=Console.ReadLine();int n=int.Parse(Console.ReadLine());for(;n-->0;){var w=Console.ReadLine();var m="";foreach(var c in w)m+=M[c-'A'];D[m]=D.GetValueOrDefault(m)+1;}Console.Write(F(0));}}